class IoTHttpClient private constructor() {

    companion object {
        private const val TAG = "IoTHttpClient"
        private const val CLOUD_BASE_URL = "https://api.example.com"
        private const val LOCAL_NETWORK_PREFIX = "192.168."
        private const val DEFAULT_TIMEOUT_SECONDS = 10L
        private const val LOCAL_TIMEOUT_SECONDS = 5L

        @Volatile
        private var instance: IoTHttpClient? = null

        fun getInstance(): IoTHttpClient {
