    private fun getClientForUrl(url: String): OkHttpClient {
        return if (isLocalNetwork(url)) localClient else secureClient
    }

    private fun isLocalNetwork(url: String): Boolean {
        return url.contains(LOCAL_NETWORK_PREFIX) ||
                url.startsWith("http://192.") ||
                url.startsWith("https://192.") ||
                url.startsWith("http://10.") ||
                url.startsWith("https://10.") ||
                url.startsWith("http://172.") ||
                url.startsWith("https://172.")
    }

    // --- Cloud API Methods ---

    fun cloudGet(endpoint: String, callback: IoTResponseCallback) {
