    // --- Local Device Methods ---

    fun deviceGet(deviceIp: String, port: Int = 80, path: String = "/", useHttps: Boolean = false, callback: IoTResponseCallback) {
        val scheme = if (useHttps) "https" else "http"
        val url = "$scheme://$deviceIp:$port$path"
        get(url, callback)
    }

    fun devicePost(deviceIp: String, port: Int = 80, path: String = "/", jsonBody: JSONObject, useHttps: Boolean = false, callback: IoTResponseCallback) {
        val scheme = if (useHttps) "https" else "http"
        val url = "$scheme://$deviceIp:$port$path"
        post(url, jsonBody, callback)
    }

    fun devicePut(deviceIp: String, port: Int = 80, path: String = "/", jsonBody: JSONObject, useHttps: Boolean = false, callback: IoTResponseCallback) {
        val scheme = if (useHttps) "https" else "http"
        val url = "$scheme://$deviceIp:$port$path"
        put(url, jsonBody, callback)
    }

    fun deviceSendCommand(deviceIp: String, port: Int = 80, command: String, params: JSONObject? = null, useHttps: Boolean = false, callback: IoTResponseCallback) {
        val body = JSONObject().apply {
            put("command", command)
            params?.let { put("params", it) }
        }
        devicePost(deviceIp, port, "/api/command", body, useHttps, callback)
    }

    fun discoverDevice(deviceIp: String, port: Int = 80, useHttps: Boolean = false, callback: IoTResponseCallback) {
        deviceGet(deviceIp, port, "/api/info", useHttps, callback)
