    // --- Core HTTP Methods ---

    fun get(url: String, headers: Map<String, String>? = null, callback: IoTResponseCallback) {
        val requestBuilder = Request.Builder()
            .url(url)
            .get()

        headers?.forEach { (key, value) ->
            requestBuilder.addHeader(key, value)
        }

        executeRequest(url, requestBuilder.build(), callback)
    }

    fun post(url: String, jsonBody: JSONObject, headers: Map<String, String>? = null, callback: IoTResponseCallback) {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder()
            .url(url)
            .post(body)

        headers?.forEach { (key, value) ->
            requestBuilder.addHeader(key, value)
        }

        executeRequest(url, requestBuilder.build(), callback)
    }

    fun put(url: String, jsonBody: JSONObject, headers: Map<String, String>? = null, callback: IoTResponseCallback) {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder()
            .url(url)
            .put(body)

        headers?.forEach { (key, value) ->
            requestBuilder.addHeader(key, value)
        }

        executeRequest(url, requestBuilder.build(), callback)
    }

    fun delete(url: String, headers: Map<String, String>? = null, callback: IoTResponseCallback) {
        val requestBuilder = Request.Builder()
            .url(url)
            .delete()

        headers?.forEach { (key, value) ->
            requestBuilder.addHeader(key, value)
        }

        executeRequest(url, requestBuilder.build(), callback)
    }

    // --- Synchronous Methods ---

    @Throws(IOException::class)
    fun getSync(url: String, headers: Map<String, String>? = null): IoTResponse {
        val requestBuilder = Request.Builder()
            .url(url)
            .get()

        headers?.forEach { (key, value) ->
            requestBuilder.addHeader(key, value)
        }

        return executeRequestSync(url, requestBuilder.build())
    }

    @Throws(IOException::class)
    fun postSync(url: String, jsonBody: JSONObject, headers: Map<String, String>? = null): IoTResponse {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder()
            .url(url)
            .post(body)

        headers?.forEach { (key, value) ->
            requestBuilder.addHeader(key, value)
        }

        return executeRequestSync(url, requestBuilder.build())
    }

    private fun executeRequest(url: String, request: Request, callback: IoTResponseCallback) {
        val client = getClientForUrl(url)

        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                Log.e(TAG, "Request failed: ${request.url}", e)
                callback.onError(IoTError(
                    message = e.message ?: "Unknown error",
                    exception = e,
                    url = url,
                    isLocalDevice = isLocalNetwork(url)
                ))
            }

            override fun onResponse(call: Call, response: Response) {
                response.use {
                    val responseBody = it.body?.string()
                    val iotResponse = IoTResponse(
                        statusCode = it.code,
                        body = responseBody,
                        headers = it.headers.toMap(),
                        url = url,
                        isLocalDevice = isLocalNetwork(url),
                        isSuccessful = it.isSuccessful
                    )

                    if (it.isSuccessful) {
                        callback.onSuccess(iotResponse)
                    } else {
                        callback.onError(IoTError(
                            message = "HTTP ${it.code}: ${it.message}",
                            statusCode = it.code,
                            responseBody = responseBody,
                            url = url,
                            isLocalDevice = isLocalNetwork(url)
                        ))
                    }
                }
            }
        })
    }

    @Throws(IOException::class)
    private fun executeRequestSync(url: String, request: Request): IoTResponse {
        val client = getClientForUrl(url)
        val response = client.newCall(request).execute()

        return response.use {
            IoTResponse(
                statusCode = it.code,
                body = it.body?.string(),
                headers = it.headers.toMap(),
                url = url,
                isLocalDevice = isLocalNetwork(url),
                isSuccessful = it.isSuccessful
            )
        }
    }

    private fun Headers.toMap(): Map<String, String> {
        val map = mutableMapOf<String, String>()
        for (i in 0 until size) {
            map[name(i)] = value(i)
        }
        return map
    }

    fun shutdown() {
        secureClient.dispatcher.executorService.shutdown()
        secureClient.connectionPool.evictAll()
        localClient.dispatcher.executorService.shutdown()
        localClient.connectionPool.evictAll()
    }

    // --- Interceptors ---

    private inner class LoggingInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val request = chain.request()
            val startTime = System.nanoTime()

            Log.d(TAG, "--> ${request.method} ${request.url}")

            val response = chain.proceed(request)

            val duration = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime)
            Log.d(TAG, "<-- ${response.code} ${request.url} (${duration}ms)")

            return response
        }
    }

    private inner class AuthInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val originalRequest = chain.request()

            // Only add auth token for cloud API requests
            if (!isLocalNetwork(originalRequest.url.toString()) && authToken != null) {
                val authenticatedRequest = originalRequest.newBuilder()
                    .addHeader("Authorization", "Bearer $authToken")
                    .build()
                return chain.proceed(authenticatedRequest)
            }

            return chain.proceed(originalRequest)
        }
    }

    // --- Data Classes ---

    data class IoTResponse(
        val statusCode: Int,
        val body: String?,
        val headers: Map<String, String>,
        val url: String,
        val isLocalDevice: Boolean,
        val isSuccessful: Boolean
    ) {
        fun bodyAsJson(): JSONObject? {
            return try {
                body?.let { JSONObject(it) }
            } catch (e: Exception) {
                null
            }
        }
    }

    data class IoTError(
        val message: String,
        val statusCode: Int? = null,
        val responseBody: String? = null,
        val exception: Exception? = null,
        val url: String,
        val isLocalDevice: Boolean
    )

    interface IoTResponseCallback {
        fun onSuccess(response: IoTResponse)
        fun onError(error: IoTError)
    }
}

// --- Example Activity Usage ---

class MainActivity : AppCompatActivity() {

    private lateinit var iotClient: IoTHttpClient

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        iotClient = IoTHttpClient.getInstance()
        iotClient.setAuthToken("your-jwt-token-here")

        // Example: Discover a local IoT device
        discoverLocalDevice("192.168.1.100")

        // Example: Send command to local IoT device
        sendCommandToDevice("192.168.1.100", "toggle_light", JSONObject().apply {
            put("brightness", 75)
            put("color", "#FF5500")
        })

        // Example: Fetch device list from cloud
        fetchDevicesFromCloud()

        // Example: Register a device with the cloud
        registerDeviceWithCloud("192.168.1.100", "Smart Light Bulb")

        // Example: GET request to local device over plain HTTP
        getDeviceStatus("192.168.1.100")

        // Example: GET request to local device over HTTPS (self-signed cert)
        getDeviceStatusSecure("192.168.1.200")
    }

    private fun discoverLocalDevice(ip: String) {
        iotClient.discoverDevice(ip, 80, false, object : IoTHttpClient.IoTResponseCallback {
            override fun onSuccess(response: IoTHttpClient.IoTResponse) {
                val json = response.bodyAsJson()
                Log.i("MainActivity", "Device discovered: ${json?.optString("name")} at $ip")
                Log.i("MainActivity", "Firmware: ${json?.optString("firmware_version")}")
                Log.i("MainActivity", "Device type: ${json?.optString("type")}")
            }

            override fun onError(error: IoTHttpClient.IoTError) {
                Log.e("MainActivity", "Discovery failed for $ip: ${error.message}")
            }
        })
    }

    private fun sendCommandToDevice(ip: String, command: String, params: JSONObject) {
        iotClient.deviceSendCommand(ip, 80, command, params, false, object : IoTHttpClient.IoTResponseCallback {
            override fun onSuccess(response: IoTHttpClient.IoTResponse) {
                Log.i("MainActivity", "Command '$command' sent successfully to $ip")
                Log.i("MainActivity", "Device response: ${response.body}")
            }

            override fun onError(error: IoTHttpClient.IoTError) {
                Log.e("MainActivity", "Command failed: ${error.message}")
            }
        })
    }

    private fun fetchDevicesFromCloud() {
        iotClient.cloudGet("/v1/devices", object : IoTHttpClient.IoTResponseCallback {
            override fun onSuccess(response: IoTHttpClient.IoTResponse) {
                val json = response.bodyAsJson()
                Log.i("MainActivity", "Cloud devices: ${json?.toString(2)}")
            }

            override fun onError(error: IoTHttpClient.IoTError) {
                Log.e("MainActivity", "Cloud fetch failed: ${error.message}, code: ${error.statusCode}")
            }
        })
    }

    private fun registerDeviceWithCloud(deviceIp: String, deviceName: String) {
        val body = JSONObject().apply {
            put("local_ip", deviceIp)
            put("name", deviceName)
            put("type", "smart_light")
        }

        iotClient.cloudPost("/v1/devices/register", body, object : IoTHttpClient.IoTResponseCallback {
            override fun onSuccess(response: IoTHttpClient.IoTResponse) {
                Log.i("MainActivity", "Device registered with cloud: ${response.body}")
            }

            override fun onError(error: IoTHttpClient.IoTError) {
                Log.e("MainActivity", "Registration failed: ${error.message}")
            }
        })
    }

    private fun getDeviceStatus(ip: String) {
        iotClient.deviceGet(ip, 80, "/api/status", false, object : IoTHttpClient.IoTResponseCallback {
            override fun onSuccess(response: IoTHttpClient.IoTResponse) {
                val json = response.bodyAsJson()
                Log.i("MainActivity", "Device status (HTTP): ${json?.toString(2)}")
            }

            override fun onError(error: IoTHttpClient.IoTError) {
                Log.e("MainActivity", "Status check failed (HTTP): ${error.message}")
            }
        })
    }

    private fun getDeviceStatusSecure(ip: String) {
        iotClient.deviceGet(ip, 443, "/api/status", true, object : IoTHttpClient.IoTResponseCallback {
            override fun onSuccess(response: IoTHttpClient.IoTResponse) {
                val json = response.bodyAsJson()
                Log.i("MainActivity", "Device status (HTTPS): ${json?.toString(2)}")
            }

            override fun onError(error: IoTHttpClient.IoTError) {
                Log.e("MainActivity", "Status check failed (HTTPS): ${error.message}")
            }
        })
    }

    override fun onDestroy() {
        super.onDestroy()
        iotClient.shutdown()
    }
}